+    fn deterministic_shuffle(values: &mut [i64], seed: u64) {
+        if values.len() <= 1 {
+            return;
+        }
+        let mut state = seed;
+        for i in (1..values.len()).rev() {
+            let j = (lcg_next(&mut state) as usize) % (i + 1);
+            values.swap(i, j);
+        }
+    }
